import { defineComponentSlotStyle } from "@yamada-ui/react"
import {
  getInputHeightStyle,
  getInputPaddingStartResetStyle,
  inputStyle,
} from "../input"

export const nativeSelectStyle = defineComponentSlotStyle({
  base: {
    field: {
      ...inputStyle.base,
      "& > option, optgroup": { bg: "bg.float" },
      _readOnly: { pointerEvents: "none" },
    },
    icon: {
      alignItems: "center",
      color: "colorScheme.outline",
      display: "inline-flex",
      fontSize: "1em",
      justifyContent: "center",
      rounded: "l1",
      _disabled: { layerStyle: "disabled" },
    },
    root: {},
  },

  variants: {
    filled: {
      field: inputStyle.variants?.filled,
    },
    flushed: {
      field: inputStyle.variants?.flushed,
      root: getInputPaddingStartResetStyle(
        "& > :is(select, [role='combobox'])",
      ),
    },
    outline: {
      field: inputStyle.variants?.outline,
    },
    plain: {
      field: inputStyle.variants?.plain,
    },
  },

  sizes: {
    xs: {
      field: { ...inputStyle.sizes?.xs, fontSize: "1em" },
      root: {
        ...getInputHeightStyle(
          inputStyle.sizes?.xs.minH,
          "& > :is(select, [role='combobox'])",
        ),
        fontSize: inputStyle.sizes?.xs.fontSize,
      },
    },
    sm: {
      field: { ...inputStyle.sizes?.sm, fontSize: "1em" },
      root: {
        ...getInputHeightStyle(
          inputStyle.sizes?.sm.minH,
          "& > :is(select, [role='combobox'])",
        ),
        fontSize: inputStyle.sizes?.sm.fontSize,
      },
    },
    md: {
      field: { ...inputStyle.sizes?.md, fontSize: "1em" },
      root: {
        ...getInputHeightStyle(
          inputStyle.sizes?.md.minH,
          "& > :is(select, [role='combobox'])",
        ),
        fontSize: inputStyle.sizes?.md.fontSize,
      },
    },
    lg: {
      field: { ...inputStyle.sizes?.lg, fontSize: "1em" },
      root: {
        ...getInputHeightStyle(
          inputStyle.sizes?.lg.minH,
          "& > :is(select, [role='combobox'])",
        ),
        fontSize: inputStyle.sizes?.lg.fontSize,
      },
    },
    xl: {
      field: { ...inputStyle.sizes?.xl, fontSize: "1em" },
      root: {
        ...getInputHeightStyle(
          inputStyle.sizes?.xl.minH,
          "& > :is(select, [role='combobox'])",
        ),
        fontSize: inputStyle.sizes?.xl.fontSize,
      },
    },
  },

  defaultProps: {
    size: "md",
    variant: "outline",
  },
})

export type NativeSelectStyle = typeof nativeSelectStyle

import type { PropsWithChildren } from "react"
import { createRef } from "react"
import { vi } from "vitest"
import { a11y, act, page, render, renderHook } from "#test/browser"
import { NativeSelect, useNativeSelect } from "."
import { FieldContext } from "../field/field"
import { BoxIcon } from "../icon"
import { InputPropsContext } from "../input"

describe("<NativeSelect />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <NativeSelect.Root placeholder="Choose a option">
        <NativeSelect.Option value="one">Option 1</NativeSelect.Option>
        <NativeSelect.Option value="two">Option 2</NativeSelect.Option>
      </NativeSelect.Root>,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(NativeSelect.Root.displayName).toBe("NativeSelectRoot")
    expect(NativeSelect.Option.displayName).toBe("NativeSelectOption")
    expect(NativeSelect.Group.displayName).toBe("NativeSelectGroup")
  })

  test("sets `className` correctly", async () => {
    const { container } = await render(
      <NativeSelect.Root
        placeholder="キャラクターを選択"
        rootProps={{ "data-testid": "root" }}
      >
        <NativeSelect.Group label="地球人">
          <NativeSelect.Option value="孫悟空">孫悟空</NativeSelect.Option>
          <NativeSelect.Option value="孫悟飯">孫悟飯</NativeSelect.Option>
          <NativeSelect.Option value="クリリン">クリリン</NativeSelect.Option>
        </NativeSelect.Group>

        <NativeSelect.Group label="フリーザ軍">
          <NativeSelect.Option value="フリーザ">フリーザ</NativeSelect.Option>
          <NativeSelect.Option value="ギニュー">ギニュー</NativeSelect.Option>
          <NativeSelect.Option value="リクーム">リクーム</NativeSelect.Option>
          <NativeSelect.Option value="バータ">バータ</NativeSelect.Option>
          <NativeSelect.Option value="ジース">ジース</NativeSelect.Option>
          <NativeSelect.Option value="グルド">グルド</NativeSelect.Option>
        </NativeSelect.Group>
      </NativeSelect.Root>,
    )

    await expect
      .element(page.getByTestId("root"))
      .toHaveClass("ui-native-select__root")
    await expect
      .element(page.getByRole("combobox", { name: /キャラクターを選択/i }))
      .toHaveClass("ui-native-select__field")
    await expect
      .element(page.getByRole("option", { name: "孫悟空" }))
      .toHaveClass("ui-native-select__option")
    expect(container.querySelector('optgroup[label="地球人"]')).toHaveClass(
      "ui-native-select__group",
    )
  })

  test("merges root props with user props in NativeSelect.Root", async () => {
    const onClickFromRoot = vi.fn()
    const onClickFromUser = vi.fn()

    await render(
      <NativeSelect.Root
        className="from-user"
        css={{ color: "rgb(255, 0, 0)" }}
        data-testid="native-select-field"
        rootProps={{
          className: "from-root",
          css: { backgroundColor: "rgb(0, 0, 255)" },
          "data-testid": "native-select-root",
          onClick: onClickFromRoot,
        }}
        onClick={onClickFromUser}
      />,
    )

    const root = page.getByTestId("native-select-root").element()
    const field = page.getByTestId("native-select-field").element()

    expect(root).toHaveClass("from-root", "from-user")
    expect(root).toHaveStyle({ color: "rgb(255, 0, 0)" })
    expect(root).toHaveStyle({ backgroundColor: "rgb(0, 0, 255)" })
    ;(field as HTMLElement).click()

    expect(onClickFromRoot).toHaveBeenCalledTimes(1)
    expect(onClickFromUser).toHaveBeenCalledTimes(1)
  })

  test("merges ref from input props context with user ref", async () => {
    const contextRef = createRef<HTMLSelectElement>()
    const userRef = createRef<HTMLSelectElement>()

    await render(
      <InputPropsContext value={{ ref: contextRef as any }}>
        <NativeSelect.Root ref={userRef} data-testid="native-select-field" />
      </InputPropsContext>,
    )

    const field = page.getByTestId("native-select-field").element()

    expect(contextRef.current).toBe(field)
    expect(userRef.current).toBe(field)
  })

  test("merges callback refs from input props context and user props once", async () => {
    const contextRef = vi.fn()
    const userRef = vi.fn()

    await render(
      <InputPropsContext value={{ ref: contextRef as any }}>
        <NativeSelect.Root ref={userRef} data-testid="native-select-field" />
      </InputPropsContext>,
    )

    const field = page.getByTestId("native-select-field").element()

    expect(contextRef).toHaveBeenCalledTimes(1)
    expect(userRef).toHaveBeenCalledTimes(1)
    expect(contextRef).toHaveBeenCalledWith(field)
    expect(userRef).toHaveBeenCalledWith(field)
  })

  test("merges focus handlers in field, root, and getter order", async () => {
    const calls: string[] = []
    const fieldOnBlur = vi.fn(() => calls.push("field-onBlur"))
    const fieldOnFocus = vi.fn(() => calls.push("field-onFocus"))
    const rootOnBlur = vi.fn(() => calls.push("root-onBlur"))
    const rootOnFocus = vi.fn(() => calls.push("root-onFocus"))
    const getterOnBlur = vi.fn(() => calls.push("getter-onBlur"))
    const getterOnFocus = vi.fn(() => calls.push("getter-onFocus"))
    const wrapper = ({ children }: PropsWithChildren) => (
      <FieldContext
        value={{
          id: "field-id",
          disabled: false,
          errorMessageId: "field-error-message",
          focused: false,
          helperMessageId: "field-helper-message",
          invalid: false,
          labelId: "field-label",
          readOnly: false,
          replace: true,
          required: false,
          onBlur: fieldOnBlur,
          onFocus: fieldOnFocus,
        }}
      >
        {children}
      </FieldContext>
    )
    const { result } = await renderHook(
      () => useNativeSelect({ onBlur: rootOnBlur, onFocus: rootOnFocus }),
      { withProvider: false, wrapper },
    )

    const fieldProps = result.current.getFieldProps({
      onBlur: getterOnBlur,
      onFocus: getterOnFocus,
    })

    act(() => {
      fieldProps.onFocus?.({} as any)
      fieldProps.onBlur?.({} as any)
    })

    expect(calls).toStrictEqual([
      "field-onFocus",
      "root-onFocus",
      "getter-onFocus",
      "field-onBlur",
      "root-onBlur",
      "getter-onBlur",
    ])
  })

  test("merges input props context with user props", async () => {
    const onClickFromRoot = vi.fn()
    const onClickFromUser = vi.fn()

    await render(
      <InputPropsContext
        value={{
          className: "from-root",
          style: { color: "rgb(255, 0, 0)" },
          onClick: onClickFromRoot,
        }}
      >
        <NativeSelect.Root
          className="from-user"
          style={{ backgroundColor: "rgb(0, 0, 255)" }}
          data-testid="native-select-field"
          rootProps={{ "data-testid": "native-select-root" }}
          onClick={onClickFromUser}
        />
      </InputPropsContext>,
    )

    const root = page.getByTestId("native-select-root").element()
    const field = page.getByTestId("native-select-field").element()

    expect(root).toHaveClass("from-root", "from-user")
    expect(field).toHaveStyle({ color: "rgb(255, 0, 0)" })
    expect(field).toHaveStyle({ backgroundColor: "rgb(0, 0, 255)" })
    ;(field as HTMLElement).click()

    expect(onClickFromRoot).toHaveBeenCalledTimes(1)
    expect(onClickFromUser).toHaveBeenCalledTimes(1)
  })

  test("should render select with props", async () => {
    const { user } = await render(
      <NativeSelect.Root
        variant="outline"
        data-testid="select"
        focusBorderColor="green.500"
        placeholder="Options"
      >
        <NativeSelect.Option value="one">Option 1</NativeSelect.Option>
        <NativeSelect.Option value="two">Option 2</NativeSelect.Option>
      </NativeSelect.Root>,
    )
    await user.selectOptions(page.getByTestId("select"), ["one"])
    const option1 = page.getByRole("option", { name: "Option 1" }).element()
    const option2 = page.getByRole("option", { name: "Option 2" }).element()

    expect((option1 as HTMLOptionElement).selected).toBeTruthy()
    expect((option2 as HTMLOptionElement).selected).toBeFalsy()
  })

  test("should render select without placeholder in options", async () => {
    const { container } = await render(
      <NativeSelect.Root
        variant="outline"
        data-testid="select"
        focusBorderColor="green.500"
        includePlaceholder={false}
        placeholder="Options"
      >
        <NativeSelect.Option data-testid="option" value="one">
          Option 1
        </NativeSelect.Option>
        <NativeSelect.Option data-testid="option" value="two">
          Option 2
        </NativeSelect.Option>
      </NativeSelect.Root>,
    )
    expect(container.querySelectorAll('[data-testid="option"]')).toHaveLength(2)
  })

  test("should disable select", async () => {
    await render(<NativeSelect.Root data-testid="select" disabled />)
    expect(page.getByTestId("select").element()).toBeDisabled()
    expect(page.getByTestId("select").element()).toHaveAttribute(
      "aria-disabled",
      "true",
    )
  })

  test("should be read only", async () => {
    await render(<NativeSelect.Root data-testid="select" readOnly />)
    expect(page.getByTestId("select").element()).toHaveAttribute(
      "aria-readonly",
      "true",
    )
    expect(page.getByTestId("select").element()).toHaveAttribute(
      "aria-disabled",
      "true",
    )
    expect(page.getByTestId("select").element()).toHaveAttribute("readonly")
  })

  test("should be invalid", async () => {
    await render(<NativeSelect.Root data-testid="select" invalid />)
    expect(page.getByTestId("select").element()).toHaveAttribute(
      "aria-invalid",
      "true",
    )
  })

  test("should render select with custom icon", async () => {
    await render(
      <NativeSelect.Root
        data-testid="select"
        iconProps={{
          children: <BoxIcon data-testid="Icon" />,
        }}
      />,
    )
    await expect.element(page.getByTestId("Icon")).toBeInTheDocument()
  })

  test("should render items correctly", async () => {
    const items: NativeSelect.Item[] = [
      { label: "孫悟空", value: "孫悟空" },
      { label: "孫悟飯", value: "孫悟飯" },
      { label: "クリリン", value: "クリリン" },
    ]
    await render(<NativeSelect.Root data-testid="select" items={items} />)
    const children = page.getByTestId("select").element().children
    expect(children).toHaveLength(3)
  })

  test("should render items with group correctly", async () => {
    const items: NativeSelect.Item[] = [
      { label: "ベジータ", value: "ベジータ" },
      {
        items: [
          { label: "孫悟空", value: "孫悟空" },
          { label: "孫悟飯", value: "孫悟飯" },
          { label: "クリリン", value: "クリリン" },
        ],
        label: "地球人",
      },
    ]
    await render(<NativeSelect.Root data-testid="select" items={items} />)
    const children = page.getByTestId("select").element().children
    expect(children).toHaveLength(2)
    const optgroup = page
      .getByTestId("select")
      .element()
      .querySelector('optgroup[label="地球人"]')
    expect(optgroup).not.toBeNull()
    expect(optgroup!.children).toHaveLength(3)
  })
})

"use client"

import type { ReactNode } from "react"
import type { HTMLProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { FieldProps } from "../field"
import type { UseInputBorderProps } from "../input"
import type { NativeSelectStyle } from "./native-select.style"
import type { UseNativeSelectProps } from "./use-native-select"
import { createSlotComponent, mergeProps } from "@yamada-ui/react"
import { useGroupItemProps } from "../group"
import { ChevronDownIcon } from "../icon"
import { InputGroup, useInputBorder, useInputPropsContext } from "../input"
import { nativeSelectStyle } from "./native-select.style"
import { useNativeSelect } from "./use-native-select"

export interface NativeSelectRootProps
  extends
    Omit<HTMLStyledProps<"select">, "size">,
    UseNativeSelectProps,
    ThemeProps<NativeSelectStyle>,
    FieldProps,
    UseInputBorderProps {
  /**
   * The icon to be used in the select.
   */
  icon?: ReactNode
  /**
   * The props for the end element.
   */
  elementProps?: InputGroup.ElementProps
  /**
   * Props for icon element.
   */
  iconProps?: NativeSelectIconProps
  /**
   * Props for root element.
   */
  rootProps?: InputGroup.RootProps
}

const {
  component,
  PropsContext: NativeSelectPropsContext,
  usePropsContext: useNativeSelectPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<NativeSelectRootProps, NativeSelectStyle>(
  "native-select",
  nativeSelectStyle,
)

export { NativeSelectPropsContext, useNativeSelectPropsContext }

/**
 * `NativeSelect` is a component used for allowing users to select one option from a list. It displays a native dropdown list provided by the browser (user agent).
 *
 * @see https://yamada-ui.com/docs/components/native-select
 */
export const NativeSelectRoot = withProvider<"select", NativeSelectRootProps>(
  (props) => {
    const [
      groupItemProps,
      {
        className,
        css,
        colorScheme,
        errorBorderColor,
        focusBorderColor,
        icon,
        elementProps,
        iconProps,
        rootProps,
        ...rest
      },
    ] = useGroupItemProps(props)
    const { getFieldProps, getIconProps, getRootProps } = useNativeSelect(rest)
    const varProps = useInputBorder({
      errorBorderColor,
      focusBorderColor,
    })

    return (
      <InputGroup.Root
        {...mergeProps(
          { className, css, colorScheme },
          getRootProps(groupItemProps),
          rootProps,
        )()}
      >
        <NativeSelectField {...getFieldProps({ ...varProps })} />

        <InputGroup.Element {...elementProps}>
          <NativeSelectIcon icon={icon} {...getIconProps(iconProps)} />
        </InputGroup.Element>
      </InputGroup.Root>
    )
  },
  "root",
)((props) => {
  const context = useInputPropsContext()

  return mergeProps(context, props)()
})

interface NativeSelectFieldProps extends HTMLStyledProps<"select"> {}

const NativeSelectField = withContext<"select", NativeSelectFieldProps>(
  "select",
  "field",
)({ "data-group-propagate": "" })

interface NativeSelectIconProps extends HTMLStyledProps {
  icon?: ReactNode
}

const NativeSelectIcon = withContext<"div", NativeSelectIconProps>(
  "div",
  "icon",
)(undefined, ({ children, icon, ...rest }) => ({
  children: icon || children || <ChevronDownIcon />,
  ...rest,
}))

export interface NativeSelectGroupProps extends HTMLProps<"optgroup"> {}

export const NativeSelectGroup = component<"optgroup", NativeSelectGroupProps>(
  "optgroup",
  "group",
)()

export interface NativeSelectOptionProps extends HTMLProps<"option"> {}

export const NativeSelectOption = component<"option", NativeSelectOptionProps>(
  "option",
  "option",
)()

export interface NativeSelectSeparatorProps extends HTMLProps<"hr"> {}

export const NativeSelectSeparator = component<
  "hr",
  NativeSelectSeparatorProps
>("hr", "separator")()

"use client"

import type { ReactNode } from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import type { FieldProps } from "../field"
import { cloneElement, useCallback, useMemo } from "react"
import { mergeProps, ariaAttr } from "@yamada-ui/react"
import { useFieldProps } from "../field"

interface NativeSelectSharedItem extends Omit<
  HTMLProps<"option">,
  "children" | "label" | "value"
> {
  label: string
}

interface NativeSelectItemWithValue extends NativeSelectSharedItem {
  value?: HTMLProps<"option">["value"]
}

interface NativeSelectItemWithItems extends NativeSelectSharedItem {
  items: NativeSelectItemWithValue[]
}

export type NativeSelectItem =
  | NativeSelectItemWithItems
  | NativeSelectItemWithValue

export interface UseNativeSelectProps extends HTMLProps<"select">, FieldProps {
  /**
   * If `true`, include placeholder in options.
   *
   * @default true
   */
  includePlaceholder?: boolean
  /**
   * If provided, generate options based on items.
   *
   * @default []
   */
  items?: NativeSelectItem[]
  /**
   * The placeholder for select.
   */
  placeholder?: string
}

export const useNativeSelect = (props: UseNativeSelectProps = {}) => {
  const {
    props: {
      children,
      disabled,
      includePlaceholder = true,
      items = [],
      placeholder,
      readOnly,
      ...rest
    },
    ariaProps,
    dataProps,
    eventProps,
  } = useFieldProps(props)
  const interactive = !(readOnly || disabled)

  const computedChildren = useMemo(() => {
    let computedChildren: ReactNode = null

    if (children) {
      computedChildren = children
    } else if (items.length) {
      computedChildren = items.map((item, index) => {
        if ("items" in item) {
          const { items, label, ...rest } = item

          return cloneElement(<optgroup />, {
            key: index,
            children: items.map(({ label, ...rest }, index) =>
              cloneElement(<option />, {
                key: index,
                children: label,
                ...rest,
              }),
            ),
            label,
            ...rest,
          })
        } else {
          const { label, ...rest } = item

          return cloneElement(<option />, {
            key: index,
            children: label,
            ...rest,
          })
        }
      })
    }

    return (
      <>
        {placeholder ? (
          <option hidden={!includePlaceholder} value="">
            {placeholder}
          </option>
        ) : null}

        {computedChildren}
      </>
    )
  }, [children, items, placeholder, includePlaceholder])

  const getRootProps: PropGetter = useCallback(
    (props) => ({ ...dataProps, ...props }),
    [dataProps],
  )

  const getFieldProps: PropGetter<"select"> = useCallback(
    ({ ref, ...props } = {}) =>
      mergeProps(
        {
          disabled,
          readOnly,
          tabIndex: interactive ? undefined : -1,
          ...ariaProps,
          ...dataProps,
          "aria-disabled": ariaAttr(!interactive),
          "aria-label": placeholder,
        },
        {
          onBlur: eventProps.onBlur,
          onFocus: eventProps.onFocus,
        },
        rest,
        props,
        {
          ref,
          children: props.children ?? computedChildren,
        },
      )(),
    [
      interactive,
      ariaProps,
      computedChildren,
      dataProps,
      eventProps,
      rest,
      placeholder,
      disabled,
      readOnly,
    ],
  )

  const getIconProps: PropGetter = useCallback(
    (props) => ({ ...dataProps, ...props }),
    [dataProps],
  )

  return { getFieldProps, getIconProps, getRootProps }
}

export type UseNativeSelectReturn = ReturnType<typeof useNativeSelect>
